description:
drh added on 2012-12-06 15:05:48:
The following script, run in "testfixture", fails, possibly with a segfault,
when db2 tries to access a collating sequence function for db1 after db1 has
been closed:
sqlite3_enable_shared_cache 1
file delete -force test.db
sqlite3 db1 test.db
sqlite3 db2 test.db
set counter 0
proc mycollate_db1 {a b} {incr ::counter; string compare $a $b}
proc mycollate_db2 {a b} {string compare $a $b}
db1 collate mycollate mycollate_db1
db2 collate mycollate mycollate_db2
db1 eval {
  CREATE TABLE t1(a, CHECK (a COLLATE mycollate IN ('one', 'two', 'three')));
  INSERT INTO t1 VALUES('one');
}
db1 close
puts counter=$counter ;# expect to see mycollate_db1 called several times
db2 eval {INSERT INTO t1 VALUES('two');}
db2 close
puts counter=$counter ;# No additional calls to mycollate_db1
